# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import SwiftUI
import UIKit

struct PromoInfo: Equatable {
    let code: String
    let discount: Int
}

final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var currentPromo: PromoInfo?
    @Published private(set) var appliedPromos: [PromoInfo] = []

    private init() {}

    @discardableResult
    func handleUniversalLink(_ url: URL) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return false
        }

        guard components.scheme?.lowercased() == "https",
              components.host?.lowercased() == "myapp.com",
              components.path.lowercased() == "/promo" else {
            return false
        }

        let items = components.queryItems ?? []
        let code = items.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let discountString = items.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

        guard !code.isEmpty,
              let discount = Int(discountString),
              (1...100).contains(discount) else {
            return false
        }

        let promo = PromoInfo(code: code, discount: discount)
        applyPromoToUserAccount(promo)
        return true
    }

    private func applyPromoToUserAccount(_ promo: PromoInfo) {
        currentPromo = promo

        if !appliedPromos.contains(promo) {
            appliedPromos.append(promo)
        }

        UserAccountManager.shared.applyPromo(code: promo.code, discount: promo.discount)
    }
}

final class UserAccountManager: ObservableObject {
    static let shared = UserAccountManager()

    @Published private(set) var promoCode: String?
    @Published private(set) var discountPercentage: Int?

    private init() {}

    func applyPromo(code: String, discount: Int) {
        promoCode = code
        discountPercentage = discount
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    func application(
        _ application: UIApplication,
        continue userActivity: NSUserActivity,
        restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void
    ) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }

        return PromoManager.shared.handleUniversalLink(url)
    }
}

@main
struct PromoCampaignApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @StateObject private var promoManager = PromoManager.shared
    @StateObject private var userAccountManager = UserAccountManager.shared

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(promoManager)
                .environmentObject(userAccountManager)
                .onOpenURL { url in
                    _ = PromoManager.shared.handleUniversalLink(url)
                }
        }
    }
}

struct ContentView: View {
    @EnvironmentObject private var promoManager: PromoManager
    @EnvironmentObject private var userAccountManager: UserAccountManager

    var body: some View {
        NavigationView {
            VStack(spacing: 16) {
                Text("Marketing Campaign Promo")
                    .font(.title2)
                    .bold()

                if let code = userAccountManager.promoCode,
                   let discount = userAccountManager.discountPercentage {
                    VStack(spacing: 8) {
                        Text("Promo Applied")
                            .font(.headline)
                            .foregroundColor(.green)

                        Text("Code: \(code)")
                        Text("Discount: \(discount)%")
                    }
                    .padding()
                } else {
